import { startOfWeek, addDays, format, parseISO, isSameDay, areIntervalsOverlapping } from "date-fns";

import { useCalendar } from "@/components/admin/calendar/contexts/calendar-context";

import { ScrollArea } from "@/components/ui/scroll-area";

import { AddBookingDialog } from "@/components/admin/calendar/components/dialogs/add-booking-dialog";
import { BookingBlock } from "@/components/admin/calendar/components/week-and-day-view/booking-block";
import { DroppableTimeBlock } from "@/components/admin/calendar/components/dnd/droppable-time-block";
import { CalendarTimeline } from "@/components/admin/calendar/components/week-and-day-view/calendar-time-line";
import { WeekViewMultiDayBookingsRow } from "@/components/admin/calendar/components/week-and-day-view/week-view-multi-day-bookings-row";

import { cn } from "@/lib/utils";
import { groupBookings, getBookingBlockStyle, isWorkingHour, getVisibleHours } from "@/components/admin/calendar/helpers";

import type { IBooking } from "@/components/admin/calendar/interfaces";

interface IProps {
  singleDayBookings: IBooking[];
  multiDayBookings: IBooking[];
}

export function CalendarWeekView({ singleDayBookings, multiDayBookings }: IProps) {
  const { selectedDate, workingHours, visibleHours } = useCalendar();

  const { hours, earliestBookingHour, latestBookingHour } = getVisibleHours(visibleHours, singleDayBookings);

  const weekStart = startOfWeek(selectedDate);
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));

  return (
    <>
      <div className="flex flex-col items-center justify-center border-b py-4 text-sm text-muted-foreground sm:hidden">
        <p>Weekly view is not available on smaller devices.</p>
        <p>Please switch to daily or monthly view.</p>
      </div>

      <div className="hidden flex-col sm:flex">
        <div>
          <WeekViewMultiDayBookingsRow selectedDate={selectedDate} multiDayBookings={multiDayBookings} />

          {/* Week header */}
          <div className="relative z-20 flex border-b">
            <div className="w-18"></div>
            <div className="grid flex-1 grid-cols-7 divide-x border-l">
              {weekDays.map((day, index) => (
                <span key={index} className="py-2 text-center text-xs font-medium text-muted-foreground">
                  {format(day, "EE")} <span className="ml-1 font-semibold text-foreground">{format(day, "d")}</span>
                </span>
              ))}
            </div>
          </div>
        </div>

        <ScrollArea className="h-[736px]" type="always">
          <div className="flex overflow-hidden">
            {/* Hours column */}
            <div className="relative w-18">
              {hours.map((hour, index) => (
                <div key={hour} className="relative" style={{ height: "96px" }}>
                  <div className="absolute -top-3 right-2 flex h-6 items-center">
                    {index !== 0 && <span className="text-xs text-muted-foreground">{format(new Date().setHours(hour, 0, 0, 0), "hh a")}</span>}
                  </div>
                </div>
              ))}
            </div>

            {/* Week grid */}
            <div className="relative flex-1 border-l">
              <div className="grid grid-cols-7 divide-x">
                {weekDays.map((day, dayIndex) => {
                  const dayBookings = singleDayBookings.filter(booking => isSameDay(parseISO(booking.startDate), day) || isSameDay(parseISO(booking.endDate), day));
                  const groupedBookings = groupBookings(dayBookings);

                  return (
                    <div key={dayIndex} className="relative">
                      {hours.map((hour, index) => {
                        const isDisabled = !isWorkingHour(day, hour, workingHours);

                        return (
                          <div key={hour} className={cn("relative", isDisabled && "bg-calendar-disabled-hour")} style={{ height: "96px" }}>
                            {index !== 0 && <div className="pointer-bookings-none absolute inset-x-0 top-0 border-b"></div>}

                            <DroppableTimeBlock date={day} hour={hour} minute={0}>
                              <AddBookingDialog startDate={day} startTime={{ hour, minute: 0 }}>
                                <div className="absolute inset-x-0 top-0 h-[24px] cursor-pointer transition-colors hover:bg-accent" />
                              </AddBookingDialog>
                            </DroppableTimeBlock>

                            <DroppableTimeBlock date={day} hour={hour} minute={15}>
                              <AddBookingDialog startDate={day} startTime={{ hour, minute: 15 }}>
                                <div className="absolute inset-x-0 top-[24px] h-[24px] cursor-pointer transition-colors hover:bg-accent" />
                              </AddBookingDialog>
                            </DroppableTimeBlock>

                            <div className="pointer-bookings-none absolute inset-x-0 top-1/2 border-b border-dashed"></div>

                            <DroppableTimeBlock date={day} hour={hour} minute={30}>
                              <AddBookingDialog startDate={day} startTime={{ hour, minute: 30 }}>
                                <div className="absolute inset-x-0 top-[48px] h-[24px] cursor-pointer transition-colors hover:bg-accent" />
                              </AddBookingDialog>
                            </DroppableTimeBlock>

                            <DroppableTimeBlock date={day} hour={hour} minute={45}>
                              <AddBookingDialog startDate={day} startTime={{ hour, minute: 45 }}>
                                <div className="absolute inset-x-0 top-[72px] h-[24px] cursor-pointer transition-colors hover:bg-accent" />
                              </AddBookingDialog>
                            </DroppableTimeBlock>
                          </div>
                        );
                      })}

                      {groupedBookings.map((group, groupIndex) =>
                        group.map(booking => {
                          let style = getBookingBlockStyle(booking, day, groupIndex, groupedBookings.length, { from: earliestBookingHour, to: latestBookingHour });
                          const hasOverlap = groupedBookings.some(
                            (otherGroup, otherIndex) =>
                              otherIndex !== groupIndex &&
                              otherGroup.some(otherBooking =>
                                areIntervalsOverlapping(
                                  { start: parseISO(booking.startDate), end: parseISO(booking.endDate) },
                                  { start: parseISO(otherBooking.startDate), end: parseISO(otherBooking.endDate) }
                                )
                              )
                          );

                          if (!hasOverlap) style = { ...style, width: "100%", left: "0%" };

                          return (
                            <div key={booking.id} className="absolute p-1" style={style}>
                              <BookingBlock booking={booking} />
                            </div>
                          );
                        })
                      )}
                    </div>
                  );
                })}
              </div>

              <CalendarTimeline firstVisibleHour={earliestBookingHour} lastVisibleHour={latestBookingHour} />
            </div>
          </div>
        </ScrollArea>
      </div>
    </>
  );
}
