"use client"

import { useState, useEffect } from "react"
import { useForm, Controller } from "react-hook-form"
import { format } from "date-fns"
import { toast } from "sonner"
import { zodResolver } from "@hookform/resolvers/zod"
import { z } from "zod"

import { useServices } from "@/lib/swr/hooks/services"
import { useCalendar } from "@/components/admin/calendar/contexts/calendar-context"

import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { TimeInput } from "@/components/ui/time-input"
import { SingleDayPicker } from "@/components/ui/single-day-picker"
import { Label } from "@/components/ui/label"
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet"
import { Loader2, ArrowRight, ArrowLeft, CheckCircle2, User, Phone, Mail, Clock, CalendarIcon, Scissors } from "lucide-react"

import type { TimeValue } from "react-aria-components"

// ─── Local Form Schema ────────────────────────────────────────────────────────
const bookingStepsSchema = z.object({
  serviceId: z.string().min(1, "Please select a service"),
  startDate: z.date({ required_error: "Please select a date" }),
  startTime: z.object({ hour: z.number(), minute: z.number() }, { required_error: "Please select a time slot" }),
  guestName: z.string().min(1, "Guest name is required"),
  guestEmail: z.string().email("Valid email is required").optional().or(z.literal("")),
  guestPhone: z.string().min(1, "Phone number is required"),
})

type FormValues = z.infer<typeof bookingStepsSchema>

interface Props {
  children?: React.ReactNode
  initialDate?: Date
  initialTime?: { hour: number; minute: number }
}

export function AddBookingSheet({ children, initialDate, initialTime }: Props) {
  const [isOpen, setIsOpen] = useState(false)
  const [step, setStep] = useState<1 | 2 | 3>(1)
  const [isSubmitting, setIsSubmitting] = useState(false)
  
  const { data: servicesData, isLoading: loadingServices } = useServices({ limit: 100 })
  const services = servicesData?.services || []

  // Initialize form
  const form = useForm<FormValues>({
    resolver: zodResolver(bookingStepsSchema),
    defaultValues: {
      serviceId: "",
      startDate: initialDate || undefined,
      startTime: initialTime || undefined,
      guestName: "",
      guestEmail: "",
      guestPhone: "",
    },
    mode: "onTouched",
  })

  // Reset/sync when open/close
  useEffect(() => {
    if (isOpen) {
      setStep(1)
      form.reset({
        serviceId: "",
        startDate: initialDate || undefined,
        startTime: initialTime || undefined,
        guestName: "",
        guestEmail: "",
        guestPhone: "",
      })
    }
  }, [isOpen, initialDate, initialTime, form])

  // Step Validation Handling
  const handleNext = async () => {
    let valid = false
    if (step === 1) {
      valid = await form.trigger(["serviceId", "startDate"])
    } else if (step === 2) {
      valid = await form.trigger(["startTime"])
    }
    if (valid) setStep((s) => (s + 1) as 1 | 2 | 3)
  }

  const handleBack = () => {
    setStep((s) => (s - 1) as 1 | 2 | 3)
  }

  const onSubmit = async (values: FormValues) => {
    setIsSubmitting(true)
    try {
      const dateStr = format(values.startDate, "yyyy-MM-dd")
      const hour = values.startTime.hour
      const minute = String(values.startTime.minute).padStart(2, "0")
      const suffix = hour >= 12 ? "PM" : "AM"
      const standardHour = hour % 12 || 12
      const timeStr = `${standardHour}:${minute} ${suffix}`

      const payload = {
        serviceIds: [values.serviceId],
        date: dateStr,
        time: timeStr,
        paymentMethod: "cash",
        userName: values.guestName,
        email: values.guestEmail || undefined,
        phone: values.guestPhone,
      }

      const res = await fetch("/api/v1/bookings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      })

      if (!res.ok) {
        let errMsg = "Failed to create booking"
        try {
          const bodyJSON = await res.json()
          if (bodyJSON.error) errMsg = bodyJSON.error
        } catch (e) {}
        throw new Error(errMsg)
      }

      toast.success("Booking created! A confirmation was scheduled.")
      setIsOpen(false)
      window.location.reload()
    } catch (err: any) {
      toast.error(err.message || "An error occurred")
    } finally {
      setIsSubmitting(false)
    }
  }

  const selectedServiceObj = services.find((s) => s.id === form.watch("serviceId"))

  return (
    <Sheet open={isOpen} onOpenChange={setIsOpen}>
      {children && (
        <div onClick={() => setIsOpen(true)} className="contents">
          {children}
        </div>
      )}
      <SheetContent className="sm:max-w-md w-full bg-slate-50 p-0 border-l overflow-y-auto flex flex-col">
        {/* Header */}
        <div className="px-6 py-5 bg-white border-b sticky top-0 z-10">
          <SheetHeader>
            <SheetTitle>New Booking</SheetTitle>
            <SheetDescription>Follow the steps to manually insert a booking into the system.</SheetDescription>
          </SheetHeader>

          {/* Stepper Wizard Indicator */}
          <div className="flex items-center justify-between mt-5 pt-1 relative">
            <div className="absolute left-0 right-0 top-1/2 h-[2px] bg-slate-100 -z-10" />
            <div className="absolute left-0 top-1/2 h-[2px] bg-blue-600 transition-all duration-300" style={{ width: step === 1 ? '0%' : step === 2 ? '50%' : '100%' }} />
            
            {[1, 2, 3].map((s) => (
              <div key={s} className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold border-2 transition-colors ${
                step > s ? 'bg-blue-600 border-blue-600 text-white' : 
                step === s ? 'bg-white border-blue-600 text-blue-600' : 'bg-white border-slate-200 text-slate-400'
              }`}>
                {step > s ? <CheckCircle2 className="w-3.5 h-3.5" /> : s}
              </div>
            ))}
          </div>
        </div>

        {/* Form Body */}
        <div className="flex-1 p-6 relative">
          <form id="booking-sheet-form" onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            
            {/* ─── STEP 1: Service & Date ─── */}
            <div className={`space-y-6 transition-all duration-300 ${step === 1 ? 'block opacity-100' : 'hidden opacity-0'}`}>
              <div className="space-y-4">
                <div className="space-y-1.5">
                  <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wide flex items-center gap-1.5">
                    <Scissors className="w-3.5 h-3.5" /> 1. Select Service
                  </Label>
                  <p className="text-xs text-muted-foreground pb-2">Which service is the client booking?</p>
                  
                  {loadingServices ? (
                    <div className="h-10 border rounded-lg flex items-center px-3 gap-2 text-sm text-slate-500">
                      <Loader2 className="w-4 h-4 animate-spin" /> Loading services...
                    </div>
                  ) : (
                    <div className="grid gap-2">
                      {services.map((svc) => (
                        <button
                          key={svc.id}
                          type="button"
                          onClick={() => {
                            form.setValue("serviceId", svc.id, { shouldValidate: true })
                          }}
                          className={`flex items-start text-left p-3 rounded-xl border transition-all ${
                            form.watch("serviceId") === svc.id 
                              ? "bg-blue-50 border-blue-600 ring-1 ring-blue-600 ring-offset-1" 
                              : "bg-white border-slate-200 hover:border-blue-300"
                          }`}
                        >
                          <div className="flex-1">
                            <p className="text-sm font-semibold text-slate-800">{svc.name}</p>
                            {svc.description && <p className="text-xs text-slate-500 mt-0.5 line-clamp-1">{svc.description}</p>}
                          </div>
                          <div className="font-medium text-sm text-slate-700 ml-3">
                            ${svc.price}
                          </div>
                        </button>
                      ))}
                    </div>
                  )}
                  {form.formState.errors.serviceId && (
                    <p className="text-destructive text-xs mt-1">{form.formState.errors.serviceId.message}</p>
                  )}
                </div>

                <div className="space-y-1.5 pt-4">
                  <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wide flex items-center gap-1.5">
                    <CalendarIcon className="w-3.5 h-3.5" /> 2. Pick a Date
                  </Label>
                  <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex justify-center">
                    <Controller
                      control={form.control}
                      name="startDate"
                      render={({ field }) => (
                        <SingleDayPicker
                          value={field.value}
                          onSelect={date => field.onChange(date as Date)}
                          className="border-0 p-0"
                          placeholder="Select Date"
                        />
                      )}
                    />
                  </div>
                  {form.formState.errors.startDate && (
                    <p className="text-destructive text-xs mt-1">{form.formState.errors.startDate.message}</p>
                  )}
                </div>
              </div>
            </div>

            {/* ─── STEP 2: Time ─── */}
            <div className={`space-y-6 transition-all duration-300 ${step === 2 ? 'block opacity-100' : 'hidden opacity-0'}`}>
              <div className="bg-white rounded-xl border border-slate-200 p-4 shadow-sm mb-6 flex items-center gap-3">
                 <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
                    <CalendarIcon className="w-5 h-5" />
                 </div>
                 <div>
                    <p className="text-xs text-muted-foreground font-medium">Selected Date</p>
                    <p className="text-sm font-semibold">{form.watch("startDate") ? format(form.watch("startDate") as Date, "EEEE, MMMM do, yyyy") : ""}</p>
                 </div>
              </div>

              <div className="space-y-1.5">
                <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wide flex items-center gap-1.5">
                  <Clock className="w-3.5 h-3.5" /> Time Slot
                </Label>
                <p className="text-xs text-muted-foreground pb-2">When should this booking occur?</p>
                <Controller
                  control={form.control}
                  name="startTime"
                  render={({ field }) => (
                    <TimeInput 
                      value={field.value as TimeValue} 
                      onChange={field.onChange} 
                      hourCycle={12} 
                      className="w-full bg-white h-12 text-lg shadow-sm"
                    />
                  )}
                />
                {form.formState.errors.startTime && (
                  <p className="text-destructive text-xs mt-1">{form.formState.errors.startTime.message}</p>
                )}
              </div>
            </div>

            {/* ─── STEP 3: Details ─── */}
            <div className={`space-y-6 transition-all duration-300 ${step === 3 ? 'block opacity-100' : 'hidden opacity-0'}`}>
              
              <div className="bg-white rounded-xl border border-slate-200 p-4 shadow-sm mb-6 text-sm">
                <h4 className="font-semibold text-slate-800 border-b pb-2 mb-2">Booking Summary</h4>
                <div className="flex justify-between py-1">
                  <span className="text-muted-foreground">Service</span>
                  <span className="font-medium text-right">{selectedServiceObj?.name}</span>
                </div>
                <div className="flex justify-between py-1">
                  <span className="text-muted-foreground">When</span>
                  <span className="font-medium text-right">
                    {form.watch("startDate") && form.watch("startTime") ? 
                      `${format(form.watch("startDate"), "MMM do")} at ${form.watch("startTime").hour%12||12}:${String(form.watch("startTime").minute).padStart(2,'0')} ${form.watch("startTime").hour>=12?'PM':'AM'}` 
                      : ''}
                  </span>
                </div>
              </div>

              <div className="space-y-4 pt-2">
                <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wide">Guest Details</h3>
                
                <div className="space-y-1.5">
                  <Label className="text-xs flex items-center gap-1.5"><User className="w-3.5 h-3.5 text-muted-foreground" /> Full Name <span className="text-destructive">*</span></Label>
                  <Input 
                    {...form.register("guestName")} 
                    placeholder="John Doe" 
                    className="bg-white h-10 shadow-sm"
                  />
                  {form.formState.errors.guestName && <p className="text-destructive text-xs">{form.formState.errors.guestName.message}</p>}
                </div>

                <div className="space-y-1.5">
                  <Label className="text-xs flex items-center gap-1.5"><Phone className="w-3.5 h-3.5 text-muted-foreground" /> Mobile Phone <span className="text-destructive">*</span></Label>
                  <Input 
                    {...form.register("guestPhone")} 
                    placeholder="+1 234 567 890" 
                    className="bg-white h-10 shadow-sm"
                  />
                  {form.formState.errors.guestPhone && <p className="text-destructive text-xs">{form.formState.errors.guestPhone.message}</p>}
                </div>

                <div className="space-y-1.5">
                  <Label className="text-xs flex items-center gap-1.5"><Mail className="w-3.5 h-3.5 text-muted-foreground" /> Email Address <span className="text-xs text-muted-foreground font-normal ml-1">(Optional, for reminders)</span></Label>
                  <Input 
                    {...form.register("guestEmail")} 
                    type="email"
                    placeholder="john@example.com" 
                    className="bg-white h-10 shadow-sm"
                  />
                  {form.formState.errors.guestEmail && <p className="text-destructive text-xs">{form.formState.errors.guestEmail.message}</p>}
                </div>
              </div>
            </div>

          </form>
        </div>

        {/* Footer Actions */}
        <div className="px-6 py-4 bg-white border-t sticky bottom-0 z-10 flex gap-2 justify-between items-center">
          {step > 1 ? (
             <Button type="button" variant="ghost" onClick={handleBack} className="gap-1 px-3">
               <ArrowLeft className="w-4 h-4" /> Back
             </Button>
          ) : (
             <Button type="button" variant="ghost" onClick={() => setIsOpen(false)} className="px-3">Cancel</Button>
          )}

          {step < 3 ? (
             <Button type="button" onClick={handleNext} className="gap-2 bg-blue-600 hover:bg-blue-700 text-white min-w-[120px]">
               Next Step <ArrowRight className="w-4 h-4" />
             </Button>
          ) : (
             <Button type="submit" form="booking-sheet-form" disabled={isSubmitting} className="gap-2 bg-blue-600 hover:bg-blue-700 text-white shadow-md min-w-[140px]">
               {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}
               Create Booking
             </Button>
          )}
        </div>
      </SheetContent>
    </Sheet>
  )
}
